  ('elementary-814ced5a-moex-00440', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '在書目紀錄功能需求（FunctionalRequirementsforBibliographicRecords,FRBR）的第二群組（group2）定 義兩種智慧與藝術創作的負責者實體（entities），至權威資料功能需求（Functional Requirements for AuthorityData,FRAD）時，則將前述實體加以擴增。下列那一個選項屬於FRAD新增的智慧與藝術創作 的負責者實體？', '["個人（person）", "家族（family）", "團體（corporatebody）", "地點（place）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00441', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '以下何種權利屬於智慧財產權？', '["債權", "抵押權", "商標權", "姓名權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00442', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '甲基金會自創辦以來，致力於雛妓救援與家暴受害者庇護，近年尤努力消彌社會中所有性/性別暴力行為 與壓迫，以建立性別公義的社會。有關甲基金會的敘述，下列何者正確？', '["和政黨一樣都是屬於非營利組織", "從民法的屬性分類屬於社團法人", "關心社會議題的層面較政黨多元", "常藉由政治參選達成該組織宗旨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00443', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '柔柔生長在一個小康的家庭，父母親從小就栽培她學習各項才藝，塑造了柔柔高雅的氣質和談吐。上述 現象最適合用下列那一種概念加以說明？', '["經濟資本", "社會資本", "象徵資本", "文化資本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00444', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '據環保團體估計，每年約有一千多萬噸的塑膠垃圾流入海中，超過 700 種海洋物種受到海洋塑膠污染的 影響，海洋垃圾也造成對船舶航行的阻礙、生態系惡化等不良影響，前述現象最適合用下列何種概念 說明？', '["外部成本內部化", "共有財的悲歌", "搭便車心態", "鄰避效應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00445', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '某甲認為年輕人自己不夠努力因此才買不起房子，某乙反駁認為，許多財團手握大筆資金投入房地產市 場，成為炒房元兇，年輕人靠著微薄的薪水，不論如何努力也永遠追不上高漲的房價。某乙的說法最接 近下列何項觀點？', '["功能論", "衝突論", "成就地位論", "人力資本論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00446', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '美國大選常見各族群文化與價值之間的激辯，但似乎都不影響美國民眾對國家的支持。請問美國人民對 國家的齊心支持，最可能基於下列何項理由？', '["公民身分的保障形成對國家的認同", "國家透過嚴密監控形成公民意識", "透過種族通婚大幅減少社會分歧", "所得平均形成強大的社會凝聚力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
